1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	const RUNE_BASE_PREMIUM = 25;
8	const THREE_ALIKE_BLOCK_PREMIUM = 60;
9	
10	const basePremiumFor = (items: Item[]): number => {
11	  const allSameType = items.length > 0 && items.every((i) => i.type === items[0].type);
12	  if (items.length === 3 && allSameType) return THREE_ALIKE_BLOCK_PREMIUM;
13	  return items.length * RUNE_BASE_PREMIUM;
14	};
15	
16	const applyFirstInsuranceSurcharge = (premium: number): number =>
17	  premium + (premium * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100;
18	
19	const quotePremium = (items: Item[]): number =>
20	  Math.ceil(applyFirstInsuranceSurcharge(basePremiumFor(items))) + PROCESSING_FEE;
21	
22	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
23	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
24	  return { results };
25	};
