const isThreeAlikeBlock = (items: Item[]): boolean =>
  items.length === 3 && items.every((i) => i.type === items[0].type);

const basePremiumFor = (items: Item[]): number =>
  isThreeAlikeBlock(items) ? THREE_ALIKE_BLOCK_PREMIUM : items.length * RUNE_BASE_PREMIUM;
